import { writeOutput } from "./codegen";

const DOCS_URL = "https://supermemory.ai/docs/api-reference";
const PLACEHOLDER_VALUE = "sm_CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocal";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Supermemory API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:supermemory",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const supermemoryFirewall = {",
    '  name: "supermemory",',
    '  description: "Supermemory",',
    "  placeholders: {",
    `    SUPERMEMORY_API_KEY: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.supermemory.ai",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.SUPERMEMORY_API_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Supermemory firewall config...");
  const ts = generateTypeScript();
  writeOutput("supermemory", ts, import.meta.dirname);
}
